mapper.select:
WITH daily_power AS ( SELECT DATE(a.upload_time) AS upload_time, SUM(a.power_value) AS cumulativePowerConsumption, GROUP_CONCAT(b.loop_name,'-',a.power_value) AS powerDataValue FROM tunnel_carbon_day_push a LEFT JOIN tunnel_power_edge_computing b on a.devicelist_id = b.devicelist_id and a.addr = b.address WHERE a.devicelist_id in
#{devicelistId}
and a.addr in
#{addrId}
and a.upload_time >= DATE_SUB(#{analyzeDto.startTime},INTERVAL 1 DAY)
and a.upload_time <= #{analyzeDto.endTime}
GROUP BY upload_time ORDER BY upload_time ), daily_power2 AS ( SELECT upload_time,cumulativePowerConsumption,powerDataValue, cumulativePowerConsumption - LAG(cumulativePowerConsumption, 1) OVER (ORDER BY upload_time) AS dailyPowerConsumption FROM daily_power order by upload_time desc ) SELECT * FROM daily_power2 where 1 = 1
and upload_time >= #{analyzeDto.startTime}

SELECT a.devicelist_id, a.addr, a.upload_time, a.power_value, b.loop_name FROM tunnel_carbon_day_push a LEFT JOIN ( SELECT devicelist_id, address, loop_name, ROW_NUMBER() OVER (PARTITION BY devicelist_id, address ORDER BY meter_index) AS rn FROM tunnel_power_edge_computing WHERE devicelist_id IN
#{devicelistId}
AND address IN
#{addrId}
) b ON a.devicelist_id = b.devicelist_id AND a.addr = b.address AND b.rn = 1 WHERE a.devicelist_id IN
#{devicelistId}
AND a.addr IN
#{addrId}
AND a.upload_time >= DATE_SUB(#{analyzeDto.startTime},INTERVAL 1 DAY)
AND a.upload_time <= #{analyzeDto.endTime}
ORDER BY upload_time

SELECT a.devicelist_id, a.addr, a.power_value, c.loop_name FROM tunnel_carbon_day_push a INNER JOIN ( SELECT devicelist_id, addr, MAX(upload_time) AS latest_upload_time FROM tunnel_carbon_day_push WHERE devicelist_id IN
#{devicelistId}
AND addr IN
#{addrId}
AND upload_time <= #{analyzeDto.endTime}
GROUP BY devicelist_id, addr ) b ON a.devicelist_id = b.devicelist_id AND a.addr = b.addr AND a.upload_time = b.latest_upload_time LEFT JOIN tunnel_power_edge_computing c ON a.devicelist_id = c.devicelist_id AND a.addr = c.address WHERE a.devicelist_id IN
#{devicelistId}
AND a.addr IN
#{addrId}
AND a.upload_time <= #{analyzeDto.endTime}
ORDER BY a.devicelist_id, a.addr

SELECT tdi.tunnel_id AS tunnelId, MIN(DATE(a.upload_time)) AS firstDate, MAX(DATE(a.upload_time)) AS lastDate FROM tunnel_carbon_day_push a INNER JOIN tunnel_devicelist_tunnelinfo tdi ON a.devicelist_id = tdi.devicelist_id AND tdi.type = 2 WHERE tdi.tunnel_id IN
#{id}
AND a.year = #{year} GROUP BY tdi.tunnel_id

SELECT COALESCE(SUM(a.power_value), 0)
FROM tunnel_carbon_day_push a
WHERE a.devicelist_id IN (
    SELECT DISTINCT tdi.devicelist_id
    FROM tunnel_devicelist_tunnelinfo tdi
    INNER JOIN t_user_tunnel u ON tdi.tunnel_id = u.tunnel_name_id AND u.user_id = #{userId}
    WHERE tdi.type = 2
)
AND DATE(a.upload_time) = #{date}

SELECT COALESCE(SUM(a.power_value), 0)
FROM tunnel_carbon_day_push a
WHERE a.devicelist_id IN (
    SELECT DISTINCT devicelist_id FROM tunnel_devicelist_tunnelinfo WHERE type = 2
)
AND DATE(a.upload_time) = #{date}

SELECT DISTINCT tdi.tunnel_id
FROM tunnel_carbon_day_push a
INNER JOIN tunnel_devicelist_tunnelinfo tdi ON a.devicelist_id = tdi.devicelist_id AND tdi.type = 2
INNER JOIN t_user_tunnel u ON tdi.tunnel_id = u.tunnel_name_id AND u.user_id = #{userId}
WHERE DATE(a.upload_time) = #{date}

SELECT COALESCE(SUM(tec.design_operating_power_total) * 24, 0)
FROM tunnel_edge_computing_terminal tec
WHERE tec.design_operating_power_total > 0
AND (
    tec.tunnel_id IN (
        SELECT DISTINCT tdi.tunnel_id
        FROM tunnel_carbon_day_push a
        INNER JOIN tunnel_devicelist_tunnelinfo tdi ON a.devicelist_id = tdi.devicelist_id AND tdi.type = 2
        INNER JOIN t_user_tunnel u ON tdi.tunnel_id = u.tunnel_name_id AND u.user_id = #{userId}
        WHERE DATE(a.upload_time) = #{date}
    )
    OR tec.id IN (
        SELECT DISTINCT tdi.tunnel_id
        FROM tunnel_carbon_day_push a
        INNER JOIN tunnel_devicelist_tunnelinfo tdi ON a.devicelist_id = tdi.devicelist_id AND tdi.type = 2
        INNER JOIN t_user_tunnel u ON tdi.tunnel_id = u.tunnel_name_id AND u.user_id = #{userId}
        WHERE DATE(a.upload_time) = #{date}
    )
)

WITH valid_pairs AS ( SELECT tpe.devicelist_id, tpe.address FROM tunnel_power_edge_computing tpe INNER JOIN tunnel_devicelist_tunnelinfo tdi ON tpe.devicelist_id = tdi.devicelist_id AND tdi.type = 2
INNER JOIN t_user_tunnel u ON tdi.tunnel_id = u.tunnel_name_id AND u.user_id = #{userId}
), meter_daily AS ( SELECT DATE(a.upload_time) AS upload_time, a.devicelist_id, a.addr, MAX(a.power_value) AS meter_cumulative FROM tunnel_carbon_day_push a INNER JOIN valid_pairs vp ON a.devicelist_id = vp.devicelist_id AND a.addr = vp.address WHERE a.upload_time >= DATE_SUB(#{date}, INTERVAL 1 DAY) AND a.upload_time <= #{date} GROUP BY DATE(a.upload_time), a.devicelist_id, a.addr ), daily_power AS ( SELECT upload_time, SUM(meter_cumulative) AS cumulativePowerConsumption FROM meter_daily GROUP BY upload_time ORDER BY upload_time ), daily_power2 AS ( SELECT upload_time, cumulativePowerConsumption, cumulativePowerConsumption - LAG(cumulativePowerConsumption, 1) OVER (ORDER BY upload_time) AS dailyPowerConsumption FROM daily_power ) SELECT COALESCE(dailyPowerConsumption, 0) FROM daily_power2 WHERE upload_time = #{date}

SELECT tdi.tunnel_id AS tunnelId, COALESCE(tnr.tunnel_name, '未知') AS tunnelName, CAST(a.month AS UNSIGNED) AS month, SUM(a.power_value) AS consumptionKwh FROM tunnel_carbon_day_push a INNER JOIN tunnel_devicelist_tunnelinfo tdi ON a.devicelist_id = tdi.devicelist_id AND tdi.type = 2 LEFT JOIN t_tunnel_name_result tnr ON tdi.tunnel_id = tnr.id
INNER JOIN t_user_tunnel u ON tdi.tunnel_id = u.tunnel_name_id AND u.user_id = #{userId}
WHERE a.year = #{year} GROUP BY tdi.tunnel_id, tnr.tunnel_name, a.month ORDER BY consumptionKwh DESC LIMIT 5

SELECT tdi.tunnel_id AS tunnelId, CAST(a.month AS UNSIGNED) AS month, COUNT(DISTINCT DATE(a.upload_time)) AS daysInMonth FROM tunnel_carbon_day_push a INNER JOIN tunnel_devicelist_tunnelinfo tdi ON a.devicelist_id = tdi.devicelist_id AND tdi.type = 2 WHERE tdi.tunnel_id IN
#{id}
AND a.year = #{year} GROUP BY tdi.tunnel_id, a.month ORDER BY tdi.tunnel_id, a.month
